from openai import OpenAI

client = OpenAI()  # reads OPENAI_API_KEY from env

# OpenAI tool definition — note the outer "type"/"function" wrapper
# and "parameters" instead of "input_schema"
weather_tool = {
    "type": "function",
    "function": {
        "name": "get_weather",
        "description": "Get current weather for a city. Returns temperature and conditions.",
        "parameters": {
            "type": "object",
            "properties": {
                "city": {
                    "type": "string",
                    "description": "City name, e.g. 'New York City'",
                },
                "units": {
                    "type": "string",
                    "enum": ["celsius", "fahrenheit"],
                    "description": "Temperature unit. Defaults to celsius.",
                },
            },
            "required": ["city"],
        },
    },
}

response = client.chat.completions.create(
    model="gpt-4o",
    messages=[{"role": "user", "content": "What's the weather in Tokyo?"}],
    tools=[weather_tool],
    tool_choice="auto",   # "auto" | "none" | {"type": "function", "function": {"name": "..."}}
)

import json
from openai import OpenAI

client = OpenAI()

def dispatch_tool(name: str, args: dict) -> str:
    if name == "get_weather":
        return json.dumps({"temp": 22, "condition": "clear"})
    return json.dumps({"error": f"Unknown tool: {name}"})

def run_openai_agent(user_message: str, tools: list) -> str:
    messages = [{"role": "user", "content": user_message}]

    for _ in range(15):
        response = client.chat.completions.create(
            model="gpt-4o",
            messages=messages,
            tools=tools,
            tool_choice="auto",
        )
        choice = response.choices[0]
        messages.append(choice.message)   # append the assistant message object

        if choice.finish_reason == "stop":
            return choice.message.content  # final text answer

        if choice.finish_reason == "tool_calls":
            for tc in choice.message.tool_calls:
                # Parse the JSON string arguments
                args = json.loads(tc.function.arguments)
                result = dispatch_tool(tc.function.name, args)

                # Tool result uses role "tool" (not "user") in OpenAI
                messages.append({
                    "role": "tool",
                    "tool_call_id": tc.id,      # matches the call's id
                    "content": result,
                })

    raise RuntimeError("Max turns exceeded")

answer = run_openai_agent("What's the weather in NYC?", [weather_tool])
print(answer)

import json
from dataclasses import dataclass
from typing import Any

@dataclass
class ToolCall:
    id: str
    name: str
    input: dict   # always a dict

@dataclass
class AgentResponse:
    text: str | None
    tool_calls: list[ToolCall]
    done: bool   # True when stop/end_turn — no more tool calls needed

def normalize_openai(response) -> AgentResponse:
    choice = response.choices[0]
    text = choice.message.content
    tcs = []
    if choice.finish_reason == "tool_calls":
        for tc in choice.message.tool_calls:
            tcs.append(ToolCall(
                id=tc.id,
                name=tc.function.name,
                input=json.loads(tc.function.arguments),   # parse string→dict
            ))
    return AgentResponse(text=text, tool_calls=tcs, done=len(tcs) == 0)

def normalize_anthropic(response) -> AgentResponse:
    text = next((b.text for b in response.content if hasattr(b, "text")), None)
    tcs = [
        ToolCall(id=b.id, name=b.name, input=b.input)   # input already dict
        for b in response.content if b.type == "tool_use"
    ]
    return AgentResponse(text=text, tool_calls=tcs, done=response.stop_reason == "end_turn")

