import json
from openai import OpenAI

client = OpenAI()

contact_extractor = {
    "type": "function",
    "function": {
        "name": "extract_contact",
        "description": "Extract contact information from text.",
        "parameters": {
            "type": "object",
            "properties": {
                "full_name":  {"type": "string"},
                "email":      {"type": "string"},
                "phone":      {"type": "string"},
                "company":    {"type": "string"},
            },
            "required": ["full_name"],
        },
    },
}

def extract_contact_openai(text: str) -> dict:
    response = client.chat.completions.create(
        model="gpt-4o",
        messages=[{"role": "user", "content": text}],
        tools=[contact_extractor],
        tool_choice={"type": "function", "function": {"name": "extract_contact"}},
    )
    tc = response.choices[0].message.tool_calls[0]
    return json.loads(tc.function.arguments)   # string → dict

result = extract_contact_openai(
    "Hi, I'm Bob Chen at Acme Inc. Email: bob@acme.com, phone: 555-1234."
)
print(result)
