import json
from openai import OpenAI
from collections import defaultdict

client = OpenAI()

def run_streaming_openai(user_message: str, tools: list) -> str:
    messages = [{"role": "user", "content": user_message}]

    for _ in range(15):
        # Accumulate the full response from the stream
        tool_calls_acc = defaultdict(lambda: {"id": "", "name": "", "arguments": ""})
        finish_reason = None
        text_acc = []

        with client.chat.completions.stream(
            model="gpt-4o",
            messages=messages,
            tools=tools,
        ) as stream:
            for chunk in stream:
                delta = chunk.choices[0].delta if chunk.choices else None
                if delta is None:
                    continue
                finish_reason = chunk.choices[0].finish_reason or finish_reason

                if delta.content:
                    print(delta.content, end="", flush=True)
                    text_acc.append(delta.content)

                if delta.tool_calls:
                    for tc_chunk in delta.tool_calls:
                        idx = tc_chunk.index
                        if tc_chunk.id:
                            tool_calls_acc[idx]["id"] = tc_chunk.id
                        if tc_chunk.function.name:
                            tool_calls_acc[idx]["name"] = tc_chunk.function.name
                        if tc_chunk.function.arguments:
                            tool_calls_acc[idx]["arguments"] += tc_chunk.function.arguments

        if finish_reason == "stop":
            return "".join(text_acc)

        if finish_reason == "tool_calls":
            # Build assistant message with complete tool calls
            tool_calls_list = []
            for idx in sorted(tool_calls_acc):
                tc = tool_calls_acc[idx]
                tool_calls_list.append({
                    "id": tc["id"],
                    "type": "function",
                    "function": {"name": tc["name"], "arguments": tc["arguments"]},
                })
            messages.append({"role": "assistant", "tool_calls": tool_calls_list})

            # Execute and return results
            for tc in tool_calls_list:
                args = json.loads(tc["function"]["arguments"])
                result = dispatch_tool(tc["function"]["name"], args)
                messages.append({
                    "role": "tool",
                    "tool_call_id": tc["id"],
                    "content": result,
                })

    raise RuntimeError("Max turns exceeded")

from openai import OpenAI
import json

client = OpenAI()

# Structured Outputs — JSON Schema in response_format
response = client.chat.completions.create(
    model="gpt-4o-2024-08-06",   # must support structured outputs
    messages=[
        {"role": "system", "content": "Extract the contact info as JSON."},
        {"role": "user",   "content": "Hi, I'm Alice at BigCorp. alice@bigcorp.com"},
    ],
    response_format={
        "type": "json_schema",
        "json_schema": {
            "name": "contact",
            "schema": {
                "type": "object",
                "properties": {
                    "full_name": {"type": "string"},
                    "email":     {"type": "string"},
                    "company":   {"type": "string"},
                },
                "required": ["full_name"],
                "additionalProperties": False,
            },
            "strict": True,
        },
    },
)
# Result is in message.content as a JSON string (not in tool_calls)
data = json.loads(response.choices[0].message.content)
print(data)
# {'full_name': 'Alice', 'email': 'alice@bigcorp.com', 'company': 'BigCorp'}
